`timescale 1ns / 1ps

module test_debouncer (
input  wire clk,
input  wire button_in,
output  wire button_out
);

          // Button debouncer with 20ms delay
      // 50 MHz clock, 20ms = 1,000,000 cycles

      localparam DEBOUNCE_COUNT = 20;  // ~20us (scaled for visibility)

      reg [$clog2(DEBOUNCE_COUNT)-1:0] debounce_counter = 0;
      reg button_sync_reg1 = 1'b0;
      reg button_sync_reg2 = 1'b0;
      reg button_state = 1'b0;

      // Double synchronizer for metastability protection
      always @(posedge clk) begin
          button_sync_reg1 <= button_in;
          button_sync_reg2 <= button_sync_reg1;
      end

      // Debounce logic
      always @(posedge clk) begin
          if (button_sync_reg2 != button_state) begin
              debounce_counter <= debounce_counter + 1'b1;
              if (debounce_counter >= DEBOUNCE_COUNT) begin
                  button_state <= button_sync_reg2;
                  debounce_counter <= 0;
              end
          end else begin
              debounce_counter <= 0;
          end
      end

      // Active-low LED output
      assign button_out = ~button_state;



endmodule
